import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Limit the length of user input to avoid buffer overflow
        int maxNameLength = 10;
        String sanitizedName = name.substring(0, Math.min(name.length(), maxNameLength));

        char[] buffer = new char[maxNameLength];

        // Copy sanitized user input into buffer
        for (int i = 0; i < sanitizedName.length(); i++) {
            buffer[i] = sanitizedName.charAt(i);
        }

        System.out.println("Buffer overflow vulnerability fixed!");
    }
}

